mapper.select:
SELECT t1.slide_id, t1.image_id, t2.image_url, t2.image_path FROM fr_slide t1 LEFT JOIN tb_image t2 ON t1.image_id = t2.image_id
AND t1.special_id = #{specialId}
AND t1.process_flag = #{processFlag}
AND t1.slide_id in
#{item}
ORDER BY t1.create_time ASC

select fs.slide_id,fs.wax_code
from fr_slide fs
         left join fr_special fsl on fs.special_id = fsl.special_id
where fsl.topic_id= #{topicId}
  and fsl.species_id= #{speciesId}
  and fsl.del_flag='0'

SELECT t2.file_name, t1.* FROM fr_slide t1 LEFT JOIN tb_image t2 on t1.image_id = t2.image_id
AND t1.special_id = #{specialId}
AND t1.animal_code = #{animalCode}
AND t2.file_name = #{fileName}
AND t1.check_status = 3
AND t1.organs like concat('%', #{categoryName}, '%')
AND t1.slide_id in
#{item}
AND t1.process_flag = 2 AND t1.check_status > 0 ORDER BY t1.animal_check_status desc,t1.check_status desc,t2.file_name
